ALTER TABLE "TradeSessionRun" ADD COLUMN "sessionType" TEXT NOT NULL DEFAULT 'REGULAR', ADD COLUMN "localSessionSlot" TEXT NOT NULL DEFAULT '12:00';
ALTER TABLE "AiFinancialWallet" ADD COLUMN "openingBalance" DECIMAL(24,8) NOT NULL DEFAULT 0, ADD COLUMN "retainedPrincipal" DECIMAL(24,8) NOT NULL DEFAULT 0;
UPDATE "AiFinancialWallet" SET "openingBalance"="availableFuture"+"lockedFuture";
UPDATE "AiFinancialWallet" w SET "retainedPrincipal"=COALESCE((SELECT (s."wallet"->>'totalFuturePrincipal')::numeric FROM "UserState" s WHERE s."userId"=w."userId"),GREATEST(0,w."openingBalance"));
ALTER TABLE "AiFinancialTrade" ALTER COLUMN "subscriptionId" DROP NOT NULL, ADD COLUMN "placementSource" TEXT NOT NULL DEFAULT 'AI_BOT', ADD COLUMN "userTimeZone" TEXT NOT NULL DEFAULT 'UTC', ADD COLUMN "localTradingDate" VARCHAR(10) NOT NULL DEFAULT '', ADD COLUMN "localSessionSlot" TEXT NOT NULL DEFAULT '';
ALTER TABLE "AiWalletLedger" ALTER COLUMN "tradeId" DROP NOT NULL;
ALTER TABLE "AiWalletLedger" DROP CONSTRAINT IF EXISTS "AiWalletLedger_trade_fkey";
ALTER TABLE "AiWalletLedger" ADD CONSTRAINT "AiWalletLedger_trade_fkey" FOREIGN KEY ("tradeId") REFERENCES "AiFinancialTrade"("id") ON DELETE RESTRICT;
CREATE TABLE "AiAdditionalTradeEligibility" ("userId" TEXT PRIMARY KEY,"sourceTransferId" TEXT NOT NULL,"firstTransferAmount" DECIMAL(24,8) NOT NULL,"eligibilityStartedAt" TIMESTAMP(3) NOT NULL,"eligibilityEndsAt" TIMESTAMP(3),"eligible" BOOLEAN NOT NULL,"consumedRuleVersion" TEXT NOT NULL DEFAULT 'FIRST_SPOT_TO_FUTURE_V1',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AiAdditionalTradeEligibility_user_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE RESTRICT);
CREATE UNIQUE INDEX "AiAdditionalTradeEligibility_sourceTransferId_key" ON "AiAdditionalTradeEligibility"("sourceTransferId");
CREATE INDEX "AiAdditionalTradeEligibility_window_idx" ON "AiAdditionalTradeEligibility"("eligible","eligibilityStartedAt","eligibilityEndsAt");
INSERT INTO "AiAdditionalTradeEligibility" ("userId","sourceTransferId","firstTransferAmount","eligibilityStartedAt","eligibilityEndsAt","eligible","createdAt","updatedAt") SELECT s."userId",first_event.entry->>'id',ABS((first_event.entry->>'amount')::numeric),to_timestamp((first_event.entry->>'timestamp')::double precision/1000),CASE WHEN ABS((first_event.entry->>'amount')::numeric)>=50 THEN to_timestamp((first_event.entry->>'timestamp')::double precision/1000)+INTERVAL '10 days' ELSE NULL END,ABS((first_event.entry->>'amount')::numeric)>=50,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP FROM "UserState" s CROSS JOIN LATERAL (SELECT entry FROM jsonb_array_elements(COALESCE(s."wallet"->'transactions','[]'::jsonb)) entry WHERE entry->>'type'='SPOT_TO_FUTURE_TRANSFER' AND entry->>'wallet'='spot' AND (entry->>'amount')::numeric<0 ORDER BY (entry->>'timestamp')::bigint ASC LIMIT 1) first_event ON TRUE ON CONFLICT ("userId") DO NOTHING;
CREATE TABLE "AiLegacyTradeMigration" ("id" TEXT PRIMARY KEY,"sourceType" TEXT NOT NULL,"sourceId" TEXT NOT NULL,"userId" TEXT NOT NULL,"authoritativeTradeId" TEXT,"classification" TEXT NOT NULL,"status" TEXT NOT NULL,"details" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AiLegacyTradeMigration_user_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE RESTRICT);
CREATE UNIQUE INDEX "AiLegacyTradeMigration_source_key" ON "AiLegacyTradeMigration"("sourceType","sourceId");
CREATE INDEX "AiLegacyTradeMigration_user_status_idx" ON "AiLegacyTradeMigration"("userId","status");
INSERT INTO "AiWalletLedger" ("id","idempotencyKey","userId","tradeId","operation","amount","availableBefore","availableAfter","lockedBefore","lockedAfter","officialAt","createdAt") SELECT 'opening:'||w."userId",'FUTURE_OPENING:'||w."userId",w."userId",NULL,'OPENING_BALANCE',w."openingBalance",0,w."openingBalance",0,0,w."createdAt",w."createdAt" FROM "AiFinancialWallet" w WHERE NOT EXISTS (SELECT 1 FROM "AiWalletLedger" l WHERE l."idempotencyKey"='FUTURE_OPENING:'||w."userId");
